        """Extracts experience details from the resume."""
        experience = []
        # This is a basic example and may need refinement based on resume format
        experience_matches = re.findall(r"(?:(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s+\d{4})\s*[-–—]\s*(?:(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s+\d{4}|Present).*\n(?:(?!\n).*\n)*", self.text) # Adjusted regex

